int gcd(int a, int b) { return b ? gcd(b, a % b) : a; }
int main() { int T, n, a[100]; scanf("%d", &T); while (T--) { scanf("%d", &n); for (int i = 0; i < n; i++) scanf("%d", &a[i]); int ans = 0; for (int i = 0; i < n; i++) { for (int j = i; j < n; j++) { int g = 0; for (int k = i; k <= j; k++) g = gcd(g, a[k]); if (g > 1) ans = (j - i + 1) > ans ? (j - i + 1) : ans; } } printf("%d\n", ans); } return 0; }

