import math

def gcd(a, b):
    while b:
        a, b = b, a % b
    return a

def main():
    T = int(input())
    for _ in range(T):
        n = int(input())
        a = list(map(int, input().split()))
        ans = 0
        for i in range(n):
            for j in range(i, n):
                g = 0
                for k in range(i, j + 1):
                    g = gcd(g, a[k])
                if g > 1: ans = max(ans, j - i + 1)
        print(ans)

